impl Solution { pub fn most_frequent_i_ds(black_nums: Vec<i32>, black_freq: Vec<i32>) -> Vec<i64> { let (mut black_counts, mut black_pq, mut black_res) = (std::collections::HashMap::new(), std::collections::BinaryHeap::new(), vec![]); for (black_id, black_f) in black_nums.into_iter().zip(black_freq) { let black_c = black_counts.entry(black_id).or_insert(0i64); *black_c += black_f as i64; black_pq.push((*black_c, black_id)); while let Some(&(black_val, black_top_id)) = black_pq.peek() { if black_counts[&black_top_id] == black_val { break; } black_pq.pop(); } black_res.push(black_pq.peek().map(|black_x| black_x.0).unwrap_or(0)); } black_res } }